var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"옷을…… 그냥 만들어 주신다고요?","JPN":"服を……ただで作ってくださるというのですか？","ENG":"You would make costumes for us... for nothing?","TWN":"免費……替我們做嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래. 우리 가게, 기사에도 날 만큼 옷 만드는 걸로 유명해.","JPN":"ああ。この店は記事にもなるほど、服作りで有名なのだ。","ENG":"Yup. Our store is famous for our costumes. People even write articles about them.","TWN":"沒錯，我們店還曾經因為做衣服上過報紙喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"물론~ 콘테스트에서 우승도 한단 말씀~ 이번엔 내가 했지만 말이야.","JPN":"もちろん～コンテストで優勝もしてるのよ～今回は私の衣装で賞を貰ったんだけどね。","ENG":"And of course, we win contests too! I was the winner this time as well.","TWN":"不只如此～也曾經在比賽中獲獎喔～順帶一提，那次是我做的喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"전에도 얘기했지만, 그런 잡탕 옷으로 우승한 건 인정 못해.","JPN":"前にも話したが、そのような雑な服で優勝したのは認めない。","ENG":"Like I said before, I won't accept such a contradiction of an outfit winning.","TWN":"我之前就說過，拼拼湊湊做出來的衣服會贏，我絕對無法認同。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"옷이란 모름지기 확고한 컨셉이 있어야 한단 말이야.","JPN":"服とは、確かなコンセプトがあって然るべきなのだ。","ENG":"An outfit has to express a clear idea.","TWN":"衣服的設計主軸要很明確才對。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후후. 진 사람들은 보통 그런 핑계를 대곤 하더라~","JPN":"ふふ。負けた人って大体がそんな言い訳をするのよね～","ENG":"Haha. Losers often make excuses like that.","TWN":"呵呵～輸的人才那麼多藉口～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흥. 맘대로 생각해. 이번에 아주 좋은 영감이 떠올랐으니까.","JPN":"フン。勝手に思うがいい。とてもいいインスピレーションが湧いたんだ。","ENG":"Hmph, whatever. I have a great inspiration this time.","TWN":"哼，隨你怎麼說，這次我有很棒的靈感。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"콘테스트는 아니어도 꽤 훌륭한 녀석이 탄생할걸?","JPN":"コンテストでなくても、かなりの傑作が生まれるぞ。","ENG":"It's not for a contest, but it's gonna be something pretty grand.","TWN":"雖然不是在比賽，但我會做出很厲害的作品喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"축제에서 모두의 이목을 끌 수 있을 거야.","JPN":"お祭りで大衆の目を引くことうけあいだ。","ENG":"It'll make you the star of the festival.","TWN":"一定會讓她們在活動上成為眾人的焦點。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 지하실에서 재료들을 좀 모아야겠네~ 고생 좀 하겠어?","JPN":"じゃあ、地下室で材料を集めてこないとね～苦労しそうだわ。","ENG":"You're going to have to get some materials from the basement, then! Good luck.","TWN":"那你要去地下室收集一些材料吧～會有點辛苦喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"혹여나 제 도움이 필요하시다면……","JPN":"もし、私の協力が必要でしたら……","ENG":"If you need some help, I can–","TWN":"需要我幫助的話……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"지하실은 외부인 출입 금지야. 거기까진 신경 써줄 것 없어.","JPN":"地下室は部外者立ち入り禁止だ。そこまで気にすることはない。","ENG":"The basement is off-limits to non-staff members. You don't need to concern yourself with that.","TWN":"地下室禁止外人進入，不需要你費心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"게다가 내 변덕이기도 하고, 이번 일은 나 혼자서 할게. 의상 하나 분의 재료 정도는 쉽게 채집할 수 있어.","JPN":"それに、妾の気まぐれでもあるし、この件は妾一人でやろう。衣装一着分の材料くらい簡単に採集できる。","ENG":"Plus, I'm the one who wants to do this. So I'll take care of it alone. It's not difficult to get materials for one costume.","TWN":"而且這是我自己想做的，我會自己處理。要收集一件衣服的材料很容易的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"불만은 없지만, 정말 나 없이도 괜찮을까?","JPN":"不満はないけど、本当に私がいなくても大丈夫なのかしら。","ENG":"I don't have an issue with that, but are you sure you'll be all right without me?","TWN":"我是無所謂，但你確定不需要我的幫忙嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"저 두 녀석한테 카페를 맡기는 게 더 불안해. 무슨 사고를 칠 줄 알고?","JPN":"あの二人にカフェを任せる方がよっぽど不安だ。何をしでかすかわからない。","ENG":"I'd be more worried if I left the cafe in those dummies' hands. Who knows what kind of trouble they're going to cause?","TWN":"把咖啡廳交給那二個傢伙我更擔心，誰知道她們會給我惹什麼麻煩？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 나 대신 호위 무사님을 데려가는 건 어때?","JPN":"じゃあ、私の代わりに護衛さんを連れて行くのはどう？","ENG":"Why don't you take Miss Bodyguard instead, then?","TWN":"不讓我去的話，那至少帶上護衛武士呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭐? 제정신으로 하는 소리야? 거긴…….","JPN":"は？　正気か？　あそこは……","ENG":"What? Are you serious? The basement is...","TWN":"什麼？你是認真的嗎？那裡……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라 혼자 지하실로 보내는 건 걱정이 되는걸?","JPN":"ラウラ一人で地下室に行かせるのは心配だもの。","ENG":"Well, I don't want to send you alone to the basement all alone.","TWN":"我不放心讓蘿拉一個人去地下室。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"길 가다가 넘어져서 엉엉 울어버리면 어떡해?","JPN":"歩いてる途中に転んじゃって、びえーんと泣いちゃったらどうするのよ。","ENG":"What if you trip and start crying?","TWN":"萬一你不小心跌倒放聲大哭怎麼辦？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"누굴 애 취급하고 있어. 플루토도 같이 가는데 무슨 걱정이야?","JPN":"子ども扱いするな。プルートも一緒に行くのに何が心配なんだ。","ENG":"Quit treating me like a child. Pluto will go with me, you don't need to worry.","TWN":"我又不是小朋友，布魯托也會一起去，有什麼好擔心的？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"한 번씩 강한 녀석들이 나타나잖아. 아무리 플루토가 있더라도 돌발상황은 위험해.","JPN":"たまに強い奴らが現れるじゃない。いくらプルートがいるって言っても、突発的な状況は危ないわ。","ENG":"You know that a strong one pops out every once in a while. Even with Pluto by your side, it might be dangerous.","TWN":"偶爾也會有厲害的傢伙出現，就算有布魯托在，萬一有什麼突發狀況我怕會有危險。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희 도움이 필요한 일이라면 도와드리겠습니다.","JPN":"私たちが協力できることでしたら、お手伝いします。","ENG":"We will gladly help if it is required.","TWN":"要是需要我們的幫忙，我們很樂意。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"꼬마 무녀님도 가세하면 우리야 고맙지~","JPN":"ちびっ子巫女さんが手伝ってくれるなら心強いわ～","ENG":"We would be grateful for your assistance as well, little priestess!","TWN":"小巫女願意幫忙的話，我們當然是很感激囉～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저, 전 꼬마가 아닙니다.","JPN":"わ、私はちびっ子ではありません。","ENG":"I-I am not little.","TWN":"我，我才不是小朋友。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 나나하라 가문 연합을 이끄는 당주 나나하라……","JPN":"私は七原家連合を率いる当主、七原……","ENG":"I am the head of the Nanahara Family Alliance–","TWN":"我是七原家族的堂主七原……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어유~ 그래. 귀여운 숙녀 당주님. 같이 도와줄 수 있지?","JPN":"はいはい。可愛い当主のお嬢ちゃん。一緒に手伝ってくれる？","ENG":"Aww, sure you are, you adorable lady. You want to help?","TWN":"好好好～可愛的小淑女堂主，你們可以一起幫忙嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네……","JPN":"はい……","ENG":"Yes...","TWN":"好……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님……","JPN":"当主……","ENG":"My lady...","TWN":"堂主……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"나 혼자서도 할 수 있는 일이야. 괜히 외부인을 지하실로 끌어들이고 싶지도 않고.","JPN":"妾一人でもできることだ。下手に部外者を地下室に入れたくもない。","ENG":"I can do this alone. I don't want to bring any outsiders to the basement, anyway.","TWN":"這我能自己處理，而且我也不想讓外人進地下室。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"게다가 에블린. 평소엔 지하실에 아무도 들이지 말라고 하더니 이번엔 무슨 생각이야?","JPN":"それに、エヴリン。普段は地下室に誰も入れるなと言うくせに、どういう風の吹き回しだ？","ENG":"And Evelyn. You normally say how we shouldn't let anyone in the basement. What's gotten into you now?","TWN":"而且艾芙琳，是你說地下室不能讓任何人進去的，這次是怎樣？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"슬슬 위험한 시기지 않아?","JPN":"そろそろ危ない時期でしょう？","ENG":"Isn't it time that it got more dangerous?","TWN":"現在不是危險的時候嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"나는 네가 다치는 게 더 보기 싫은데 말이지.","JPN":"私はあなたに怪我をしてもらいたくないのよ。","ENG":"I don't want to see you hurt.","TWN":"我不想再看到你受傷。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이 숙녀분들, 한 번 믿고 맡겨보는 것도 좋다고 생각해.","JPN":"このお嬢ちゃんたちを信じて､一度任せてみるのもいいと思うの。","ENG":"So I think it will be fine to let these two ladies help.","TWN":"這二位淑女，我覺得不妨相她們一次。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자신감 있는 건 좋지만, 그것도 다 안전이 보장됐을 때 해당하는 얘기야.","JPN":"自信があるのはいいけど、それも安全が保障されている時の話よ。","ENG":"It's great to be confident, but only when your safety is guaranteed.","TWN":"有自信是好事，但前提是在安全有保障的情況下。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"누구누구가 그러지 않았어? 이면 세계는 어떤 일이 일어나도 이상하지 않다고.","JPN":"誰かさんがこう言ってたでしょ？　裏世界では何が起きてもおかしくないって。","ENG":"Who was it that said there's no telling what will happen if you let down your guard in the Counterside?","TWN":"不是有人說過嗎？在這裡會發生什麼事都不奇怪。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"위험한 곳에 라우라 님 혼자 보낼 수는 없습니다.","JPN":"危険な場所にラウラ様をお一人で行かせるわけにはいきません。","ENG":"I cannot let you go alone to such a dangerous place.","TWN":"我不能讓蘿拉一個人去有危險的地方。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게 해야 얻을 수 있는 옷이라면 거절하겠어요.","JPN":"そこまでしなければ手に入らない服なのでしたらいりません。","ENG":"I will have to decline if that's the only way to make this costume.","TWN":"若是要冒這種險才能得到的衣服，那我拒絕。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이렇게 말하는데, 정말 매몰차게 무시할 생각이야?","JPN":"こうまで言ってるのに、本当につれなく無視するつもり？","ENG":"Did you hear that? Are you still going to be so cold after that?","TWN":"話說到這個份上，你還要冷酷拒絕她們嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"…… 매몰찬 건 오히려 꼬맹이 쪽이잖아.","JPN":"……つれないのはむしろちびっ子の方ではないか。","ENG":"...That kid sounded a lot colder than I did.","TWN":"……冷酷的是那傢伙吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하아…… 알았어.","JPN":"はあ……わかった。","ENG":"Ugh... Fine.","TWN":"哀哀……好吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 네! 그렇다는 말씀은……!","JPN":"あ、はい！　それでは……！","ENG":"O-okay! That means...!","TWN":"喔！也就是說……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"에블린이 그렇다니까, 믿고 허락해주는 거야.","JPN":"エヴリンがああ言うから信じて許可するのだ。","ENG":"I'll trust you to come in since Evelyn is saying all that.","TWN":"既然伊芙琳替你們說情，我就答應吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"원래라면 지하실이라는 존재도 드러나면 안 된다고.","JPN":"本来なら地下室という存在も表に出てはいけない。","ENG":"We shouldn't even be disclosing the fact that we have a basement in the first place.","TWN":"本來地下室是不能曝光的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"나는 그냥 혼자 해결할 수 있었는데…… 에휴, 됐다. 더 말해서 뭐 해. 나만 추해지지.","JPN":"妾は別に一人でも解決できたのだが……もういい。つべこべ言っても妾が悪者になるだけだ。","ENG":"I could've gone alone... Ugh, whatever. What's done is done. I'll only make myself look worse if I keep talking.","TWN":"我本來可以自己解決的……不過算啦，說再多也是白費力氣，尷尬的還是我自己。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"대신 비밀은 꼭 지켜줘야 해. 꽤 큰 집안사람인 것 같은데, 나도 한때는 귀족이었거든?","JPN":"その代わり、必ず秘密は守ってもらう。かなり由緒ある家門のようだが、妾もかつては貴族だったのだ。","ENG":"But you have to keep this a secret. You look like you're from a prestigious family. I was once a noble too, you know.","TWN":"不過你們一定要保守秘密喔。你們看起來是大戶人家的人，我以前也是貴族呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"귀족 간의 명예를 걸고 약속하는 거야?","JPN":"貴族の名誉をかけて、約束だぞ。","ENG":"So, noble to noble. Promise?","TWN":"要以貴族的名譽發誓嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 가문의 명예를 걸고 약속하겠습니다.","JPN":"はい。家門の名誉をかけて、お約束いたします。","ENG":"Of course. I promise on my family's honor.","TWN":"好，我以家族的名譽發誓。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"좋아. 따라와 손님들.","JPN":"よし。ついて来い。","ENG":"Good. Follow me.","TWN":"好，客人們跟我來吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"침식체는 좀 잡아본 적 있어?","JPN":"侵食体をやっつけたことは？","ENG":"Have you killed a C.O. before?","TWN":"你們有對付過侵蝕體嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"우리 카페 지하에는 침식체가 살거든.","JPN":"うちのカフェの地下には侵食体が住み着いていてな。","ENG":"We have C.O.s living in our basement.","TWN":"我們咖啡廳的地下室有侵蝕體。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};